from django.shortcuts import render, redirect
from django.http import HttpResponse
from django.contrib.auth import login
from django.contrib.auth.models import User
from django.views import View
from lxml import etree
from django.conf import settings
import base64

class SAMLResponseView(View):
    def post(self, request):
        saml_response = request.POST.get('SAMLResponse')
        if not saml_response:
            return HttpResponse("Missing SAML Response", status=400)

        saml_response_decoded = base64.b64decode(saml_response)
        xml_tree = etree.fromstring(saml_response_decoded)

        if not self.validate_xml(xml_tree):
            return HttpResponse("Invalid SAML Response", status=400)

        name_id = self.get_name_id(xml_tree)
        attributes = self.get_attributes(xml_tree)

        user = self.create_or_get_user(name_id, attributes)
        login(request, user)

        return redirect(settings.LOGIN_REDIRECT_URL)

    def validate_xml(self, xml_tree):
        # Basic structure validation
        try:
            # Check for the expected root element
            assert xml_tree.tag.endswith('Response')
            return True
        except AssertionError:
            return False

    def get_name_id(self, xml_tree):
        name_id_element = xml_tree.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}NameID')
        return name_id_element.text if name_id_element is not None else None

    def get_attributes(self, xml_tree):
        attributes = {}
        for attr in xml_tree.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}Attribute'):
            attr_name = attr.get('Name')
            attr_value = attr.find('{urn:oasis:names:tc:SAML:2.0:assertion}AttributeValue').text
            attributes[attr_name] = attr_value
        return attributes

    def create_or_get_user(self, name_id, attributes):
        user, created = User.objects.get_or_create(username=name_id)
        # Update user attributes based on SAML attributes if needed
        if created:
            user.email = attributes.get('email', '')
            user.first_name = attributes.get('firstName', '')
            user.last_name = attributes.get('lastName', '')
            user.save()
        return user

